import{_ as n,o as t,c as s,a4 as l}from"./chunks/framework._in6GHBg.js";const u=JSON.parse('{"title":"三角函数与解三角形套路","description":"","frontmatter":{},"headers":[],"relativePath":"math/Math-Review-Routine-003-三角函数套路-V1.0-20260405.md","filePath":"math/Math-Review-Routine-003-三角函数套路-V1.0-20260405.md"}'),i={name:"math/Math-Review-Routine-003-三角函数套路-V1.0-20260405.md"};function e(r,a,p,o,h,c){return t(),s("div",null,[...a[0]||(a[0]=[l(`<h1 id="三角函数与解三角形套路" tabindex="-1">三角函数与解三角形套路 <a class="header-anchor" href="#三角函数与解三角形套路" aria-label="Permalink to &quot;三角函数与解三角形套路&quot;">​</a></h1><p><strong>识别→转化→计算→验证</strong></p><hr><h2 id="一、题型识别" tabindex="-1">一、题型识别 <a class="header-anchor" href="#一、题型识别" aria-label="Permalink to &quot;一、题型识别&quot;">​</a></h2><h3 id="特征关键词" tabindex="-1">特征关键词 <a class="header-anchor" href="#特征关键词" aria-label="Permalink to &quot;特征关键词&quot;">​</a></h3><ul><li>&quot;求三角函数值&quot;</li><li>&quot;化简&quot;</li><li>&quot;证明三角恒等式&quot;</li><li>&quot;解三角形&quot;</li><li>&quot;求角A的大小&quot;</li><li>&quot;求三角形的面积&quot;</li></ul><h3 id="典型问法" tabindex="-1">典型问法 <a class="header-anchor" href="#典型问法" aria-label="Permalink to &quot;典型问法&quot;">​</a></h3><ul><li>已知sinα，求cosα、tanα</li><li>化简：sin(π+α)·cos(π-α)</li><li>证明：左边 = 右边</li><li>在△ABC中，已知a,b,c，求角C</li><li>求三角函数的最值</li></ul><hr><h2 id="二、解题步骤" tabindex="-1">二、解题步骤 <a class="header-anchor" href="#二、解题步骤" aria-label="Permalink to &quot;二、解题步骤&quot;">​</a></h2><h3 id="类型1-诱导公式化简" tabindex="-1">类型1：诱导公式化简 <a class="header-anchor" href="#类型1-诱导公式化简" aria-label="Permalink to &quot;类型1：诱导公式化简&quot;">​</a></h3><p><strong>Step 1：确定角的形式</strong></p><ul><li>看是否是π±α、π/2±α、-α等形式</li></ul><p><strong>Step 2：应用口诀</strong></p><ul><li>&quot;奇变偶不变，符号看象限&quot;</li><li>奇偶：看π/2的系数</li><li>符号：把α看成锐角，看原函数在对应象限的符号</li></ul><p><strong>Step 3：化简计算</strong></p><ul><li>化到最简形式</li></ul><p><strong>常见错误</strong>：</p><ul><li>符号判断错误</li><li>忘记&quot;变&quot;函数名</li></ul><hr><h3 id="类型2-同角三角函数求值" tabindex="-1">类型2：同角三角函数求值 <a class="header-anchor" href="#类型2-同角三角函数求值" aria-label="Permalink to &quot;类型2：同角三角函数求值&quot;">​</a></h3><p><strong>已知sinα，求cosα、tanα</strong></p><p><strong>Step 1：确定象限</strong></p><ul><li>根据已知条件和α的范围，确定α所在象限</li><li>确定sin、cos、tan的符号</li></ul><p><strong>Step 2：用平方关系</strong></p><ul><li>sin²α + cos²α = 1 → 求cosα</li></ul><p><strong>Step 3：用商数关系</strong></p><ul><li>tanα = sinα/cosα</li></ul><p><strong>注意</strong>：</p><ul><li>开方时注意正负号</li><li>不确定象限时可能有多个解</li></ul><hr><h3 id="类型3-三角恒等变换" tabindex="-1">类型3：三角恒等变换 <a class="header-anchor" href="#类型3-三角恒等变换" aria-label="Permalink to &quot;类型3：三角恒等变换&quot;">​</a></h3><p><strong>Step 1：观察角的关系</strong></p><ul><li>2α和α → 用二倍角公式</li><li>α±β → 用和差角公式</li><li>既有sin又有cos → 考虑辅助角公式</li></ul><p><strong>Step 2：观察函数名</strong></p><ul><li>&quot;切化弦&quot;或&quot;弦化切&quot;</li><li>统一函数名</li></ul><p><strong>Step 3：观察次数</strong></p><ul><li>二次 → 用降幂公式降为一次</li></ul><p><strong>公式选择口诀</strong>：</p><ul><li>角优先：先看角的关系</li><li>次优先：二次降幂</li><li>名统一：统一函数名</li></ul><hr><h3 id="类型4-解三角形" tabindex="-1">类型4：解三角形 <a class="header-anchor" href="#类型4-解三角形" aria-label="Permalink to &quot;类型4：解三角形&quot;">​</a></h3><p><strong>Step 1：分析已知条件</strong></p><ul><li>已知两角一边 → 正弦定理</li><li>已知两边一对角 → 正弦定理（注意多解）</li><li>已知两边夹角 → 余弦定理</li><li>已知三边 → 余弦定理</li></ul><p><strong>Step 2：选择定理</strong></p><table tabindex="0"><thead><tr><th style="text-align:center;">已知条件</th><th style="text-align:center;">选用定理</th></tr></thead><tbody><tr><td style="text-align:center;">两角一边</td><td style="text-align:center;">正弦定理</td></tr><tr><td style="text-align:center;">两边一对角</td><td style="text-align:center;">正弦定理（注意多解）</td></tr><tr><td style="text-align:center;">两边夹角</td><td style="text-align:center;">余弦定理</td></tr><tr><td style="text-align:center;">三边</td><td style="text-align:center;">余弦定理</td></tr><tr><td style="text-align:center;">求面积</td><td style="text-align:center;">S = (1/2)ab·sinC</td></tr></tbody></table><p><strong>Step 3：列方程求解</strong></p><p><strong>Step 4：检验合理性</strong></p><ul><li>三角形内角和 = 180°</li><li>大边对大角，小边对小角</li><li>两边之和大于第三边</li></ul><p><strong>多解情况判断</strong>：</p><ul><li>已知两边一对角（SSA），可能有两解、一解、无解</li><li>用正弦定理求出sin值后，看是否sin &gt; 1（无解）</li><li>sin ≤ 1时，看对应角是锐角还是钝角都可能</li></ul><hr><h3 id="类型5-三角函数图像与性质" tabindex="-1">类型5：三角函数图像与性质 <a class="header-anchor" href="#类型5-三角函数图像与性质" aria-label="Permalink to &quot;类型5：三角函数图像与性质&quot;">​</a></h3><p><strong>Step 1：化为标准形式</strong></p><ul><li>y = Asin(ωx + φ) + B</li></ul><p><strong>Step 2：确定参数</strong></p><ul><li>A：振幅（最大值-最小值）/2</li><li>ω：角频率，周期T = 2π/|ω|</li><li>φ：初相</li><li>B：上下平移（中线）</li></ul><p><strong>Step 3：求性质</strong></p><ul><li>最值：最大值 = A + B，最小值 = -A + B</li><li>单调区间：解不等式</li><li>对称轴：ωx + φ = π/2 + kπ</li><li>对称中心：ωx + φ = kπ</li></ul><hr><h2 id="三、标准格式" tabindex="-1">三、标准格式 <a class="header-anchor" href="#三、标准格式" aria-label="Permalink to &quot;三、标准格式&quot;">​</a></h2><h3 id="解三角形答题模板" tabindex="-1">解三角形答题模板 <a class="header-anchor" href="#解三角形答题模板" aria-label="Permalink to &quot;解三角形答题模板&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>解：在△ABC中，</span></span>
<span class="line"><span>由正弦定理/余弦定理：</span></span>
<span class="line"><span>[列出方程]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>解得：[结果]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>检验：[合理性检验]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>答：[最终答案]</span></span></code></pre></div><h3 id="化简题答题模板" tabindex="-1">化简题答题模板 <a class="header-anchor" href="#化简题答题模板" aria-label="Permalink to &quot;化简题答题模板&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>解：原式 = [逐步化简]</span></span>
<span class="line"><span>       = [中间步骤]</span></span>
<span class="line"><span>       = [最简结果]</span></span></code></pre></div><hr><h2 id="四、典型例题" tabindex="-1">四、典型例题 <a class="header-anchor" href="#四、典型例题" aria-label="Permalink to &quot;四、典型例题&quot;">​</a></h2><h3 id="例题1-诱导公式化简" tabindex="-1">例题1：诱导公式化简 <a class="header-anchor" href="#例题1-诱导公式化简" aria-label="Permalink to &quot;例题1：诱导公式化简&quot;">​</a></h3><p><strong>题目</strong>：化简 sin(π+α)·cos(π-α)·tan(-α)</p><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>解：sin(π+α) = -sinα  （π是π/2的2倍，偶；π+α在第三象限，sin为负）</span></span>
<span class="line"><span>   cos(π-α) = -cosα  （π是偶；π-α在第二象限，cos为负）</span></span>
<span class="line"><span>   tan(-α) = -tanα   （tan是奇函数）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>原式 = (-sinα)·(-cosα)·(-tanα)</span></span>
<span class="line"><span>     = -sinα·cosα·(sinα/cosα)</span></span>
<span class="line"><span>     = -sin²α</span></span></code></pre></div><hr><h3 id="例题2-解三角形" tabindex="-1">例题2：解三角形 <a class="header-anchor" href="#例题2-解三角形" aria-label="Permalink to &quot;例题2：解三角形&quot;">​</a></h3><p><strong>题目</strong>：在△ABC中，a=√3，b=1，B=30°，求A、C、c。</p><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>解：由正弦定理：a/sinA = b/sinB</span></span>
<span class="line"><span></span></span>
<span class="line"><span>√3/sinA = 1/sin30° = 2</span></span>
<span class="line"><span>sinA = √3/2</span></span>
<span class="line"><span></span></span>
<span class="line"><span>∴ A = 60° 或 A = 120°</span></span>
<span class="line"><span></span></span>
<span class="line"><span>情况1：A = 60°</span></span>
<span class="line"><span>则 C = 180° - 60° - 30° = 90°</span></span>
<span class="line"><span>c = b·sinC/sinB = 1·1/(1/2) = 2</span></span>
<span class="line"><span></span></span>
<span class="line"><span>情况2：A = 120°</span></span>
<span class="line"><span>则 C = 180° - 120° - 30° = 30°</span></span>
<span class="line"><span>c = b·sinC/sinB = 1·(1/2)/(1/2) = 1</span></span>
<span class="line"><span></span></span>
<span class="line"><span>检验：两种情况都满足三角形条件</span></span>
<span class="line"><span>答：A=60°, C=90°, c=2 或 A=120°, C=30°, c=1</span></span></code></pre></div><hr><h2 id="五、变式训练" tabindex="-1">五、变式训练 <a class="header-anchor" href="#五、变式训练" aria-label="Permalink to &quot;五、变式训练&quot;">​</a></h2><h3 id="变式1-角的变形" tabindex="-1">变式1：角的变形 <a class="header-anchor" href="#变式1-角的变形" aria-label="Permalink to &quot;变式1：角的变形&quot;">​</a></h3><ul><li>题目中出现2α、α/2、α+β等复合角</li><li>应对：先用和差角或二倍角公式展开</li></ul><h3 id="变式2-范围限制" tabindex="-1">变式2：范围限制 <a class="header-anchor" href="#变式2-范围限制" aria-label="Permalink to &quot;变式2：范围限制&quot;">​</a></h3><ul><li>题目给出α的范围（如0&lt;α&lt;π/2）</li><li>应对：根据范围确定三角函数值的符号</li></ul><h3 id="变式3-最值问题" tabindex="-1">变式3：最值问题 <a class="header-anchor" href="#变式3-最值问题" aria-label="Permalink to &quot;变式3：最值问题&quot;">​</a></h3><ul><li>求Asinx + Bcosx的最值</li><li>应对：用辅助角公式化为√(A²+B²)sin(x+φ)</li></ul><hr><h2 id="六、易错点清单" tabindex="-1">六、易错点清单 <a class="header-anchor" href="#六、易错点清单" aria-label="Permalink to &quot;六、易错点清单&quot;">​</a></h2><h3 id="审题阶段" tabindex="-1">审题阶段 <a class="header-anchor" href="#审题阶段" aria-label="Permalink to &quot;审题阶段&quot;">​</a></h3><ul><li>[ ] 角的范围是否看清？</li><li>[ ] 是求值还是化简？</li><li>[ ] 是三角函数值还是角度？</li></ul><h3 id="计算阶段" tabindex="-1">计算阶段 <a class="header-anchor" href="#计算阶段" aria-label="Permalink to &quot;计算阶段&quot;">​</a></h3><ul><li>[ ] 诱导公式符号是否正确？</li><li>[ ] 开方时正负号是否考虑？</li><li>[ ] 解三角形时是否检验多解？</li></ul><h3 id="检验阶段" tabindex="-1">检验阶段 <a class="header-anchor" href="#检验阶段" aria-label="Permalink to &quot;检验阶段&quot;">​</a></h3><ul><li>[ ] 结果是否在合理范围内？</li><li>[ ] 特殊角值是否计算正确？</li><li>[ ] 单位是否统一（角度制/弧度制）？</li></ul><hr><h2 id="七、得分点提示" tabindex="-1">七、得分点提示 <a class="header-anchor" href="#七、得分点提示" aria-label="Permalink to &quot;七、得分点提示&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">步骤</th><th style="text-align:left;">得分点</th></tr></thead><tbody><tr><td style="text-align:center;">诱导公式</td><td style="text-align:left;">写出每一步的变换依据</td></tr><tr><td style="text-align:center;">解三角形</td><td style="text-align:left;">写明使用正弦/余弦定理</td></tr><tr><td style="text-align:center;">多解情况</td><td style="text-align:left;">讨论不同情况</td></tr><tr><td style="text-align:center;">检验</td><td style="text-align:left;">写出合理性检验</td></tr></tbody></table><hr><p><strong>文档编号</strong>: Math-Review-Routine-003<br><strong>版本</strong>: V1.0<br><strong>日期</strong>: 20260405</p>`,97)])])}const g=n(i,[["render",e]]);export{u as __pageData,g as default};
